 36→// 获取适当的命令和参数
 37→function getNpxCommand() {
 38→  if (isWindows) {
 39→    // Windows: 使用 cmd.exe
 40→    return {
 41→      command: 'cmd',
 42→      args: ['/c', 'npx', '-y', 'playwright', 'install', 'chromium'],
 43→      shell: false
 44→    };
 45→  } else {
 46→    // Unix-like: 直接使用 npx
 47→    return {
 48→      command: 'npx',
