 55→// 检查并安装 Playwright
 56→async function ensurePlaywright() {
 57→  try {
 58→    // 尝试导入 playwright
 59→    await import('playwright');
 60→    return true;
 61→  } catch (error) {
 62→    console.log('⚠️  未检测到 Playwright,正在自动安装...');
