 64→
 65→    return new Promise((resolve, reject) => {
 66→      const { command, args, shell } = getNpxCommand();
 67→
 68→      // 安装 playwright
 69→      const install = spawn(command, args, {
 70→        stdio: 'inherit',
 71→        shell
 72→      });
 73→
 74→      install.on('close', (code) => {
 75→        if (code === 0) {
 76→          console.log('\n✅ Playwright 安装完成！');
