281→/**
282→ * 下载单个图片
283→ * @param {string} url - 图片URL
284→ * @param {string} filepath - 保存路径
285→ * @returns {Promise<void>}
286→ */
287→function downloadImage(url, filepath) {
288→  return new Promise((resolve, reject) => {
289→    const protocol = url.startsWith('https') ? https : http;
290→    const request = protocol.get(url, (response) => {
291→      // 处理重定向
292→      if (response.statusCode === 301 || response.statusCode === 302) {
293→        downloadImage(response.headers.location, filepath).then(resolve).catch(reject);
294→        return;
295→      }
296→
297→      if (response.statusCode !== 200) {
298→        reject(new Error(`下载图片失败: ${response.statusCode}`));
299→        return;
300→      }
301→
302→      const fileStream = createWriteStream(filepath);
303→      response.pipe(fileStream);
304→
305→      fileStream.on('finish', () => {
306→        fileStream.close();
307→        resolve();
308→      });
309→
310→      fileStream.on('error', (err) => {
311→        // 删除不完整的文件
312→        try {
313→          const fs = require('fs');
314→          fs.unlink(filepath, () => {});
315→        } catch (e) {}
316→        reject(err);
317→      });
318→    });
319→
320→    request.on('error', reject);
321→    request.setTimeout(30000, () => {
322→      request.destroy();
323→      reject(new Error('下载图片超时'));
324→    });
325→  });
326→}
