328→/**
329→ * 批量下载图片
330→ * @param {Array} images - 图片信息数组 [{url, alt, index}]
331→ * @param {string} imagesDir - 图片保存目录
332→ * @returns {Promise<Object>} 图片索引到文件名的映射
333→ */
334→async function downloadImages(images, imagesDir) {
335→  if (!images || images.length === 0) {
336→    return {};
337→  }
338→
339→  console.log(`\n📥 发现 ${images.length} 张图片，开始下载...`);
340→
341→  // 确保图片目录存在
342→  if (!existsSync(imagesDir)) {
343→    await mkdir(imagesDir, { recursive: true });
344→  }
345→
346→  const imageMap = {};
347→  let successCount = 0;
348→  let failCount = 0;
349→  let filteredCount = 0;
350→
351→  for (let i = 0; i < images.length; i++) {
352→    const img = images[i];
353→    try {
354→      // 从 URL 中提取文件扩展名，如果没有则使用 .jpg
355→      let ext = '.jpg';
356→      const urlMatch = img.url.match(/\.([a-z]{3,4})(?:\?|$)/i);
357→      if (urlMatch) {
358→        ext = '.' + urlMatch[1].toLowerCase();
359→      }
360→
361→      // 生成文件名：使用时间戳和索引避免重名
362→      const filename = `image_${Date.now()}_${i}${ext}`;
363→      const filepath = join(imagesDir, filename);
364→
365→      // 下载图片
366→      await downloadImage(img.url, filepath);
367→
368→      // 检查文件大小，过滤掉太小的图片
369→      if (IMAGE_FILTER_CONFIG.enabled) {
370→        const stats = await stat(filepath);
371→        const fileSize = stats.size;
372→
373→        if (fileSize < IMAGE_FILTER_CONFIG.minFileSize) {
374→          // 删除太小的图片
375→          await unlink(filepath);
376→          filteredCount++;
377→          const sizeKB = (fileSize / 1024).toFixed(2);
378→          console.log(`  🔍 [${i + 1}/${images.length}] 已过滤 (${sizeKB}KB < ${IMAGE_FILTER_CONFIG.minFileSize / 1024}KB): ${img.alt}`);
379→          continue;
380→        }
381→      }
382→
383→      imageMap[i] = {
384→        filename: filename,
385→        alt: img.alt
386→      };
387→      successCount++;
388→      console.log(`  ✅ [${i + 1}/${images.length}] ${img.alt}`);
389→    } catch (error) {
390→      failCount++;
391→      console.log(`  ❌ [${i + 1}/${images.length}] 下载失败: ${error.message}`);
392→    }
393→  }
394→
395→  console.log(`📊 图片下载完成: 成功 ${successCount} 张, 过滤 ${filteredCount} 张, 失败 ${failCount} 张\n`);
396→
397→  return imageMap;
398→}
