405→async function saveAsMarkdown(article, outputPath) {
406→  try {
407→    // 规范化文件名（移除非法字符）
408→    const safeTitle = article.title
409→      .replace(/[<>:"/\\|?*]/g, '') // 移除 Windows 非法字符
410→      .replace(/\s+/g, '_') // 空格替换为下划线
411→      .substring(0, 100); // 限制长度
412→
413→    // 检查是目录还是文件路径
414→    let finalPath = outputPath;
415→    try {
416→      const stats = await stat(outputPath);
417→      if (stats.isDirectory()) {
418→        // 如果是目录，使用标题作为文件名
419→        finalPath = join(outputPath, `${safeTitle}.md`);
420→      }
421→    } catch {
422→      // 路径不存在或不是目录，直接使用给定的路径
423→      // 确保路径以 .md 结尾
424→      if (!finalPath.endsWith('.md')) {
425→        finalPath = `${finalPath}.md`;
426→      }
427→    }
428→
429→    // 确保目录存在
430→    const dir = dirname(finalPath);
431→    if (!existsSync(dir)) {
432→      await mkdir(dir, { recursive: true });
433→    }
434→
435→    // 下载图片并获取图片映射
436→    let content = article.content;
437→    let imagesDir = null;
438→
439→    if (article.images && article.images.length > 0) {
440→      // 创建图片保存目录（与 Markdown 文件同名）
441→      const mdFileBasename = finalPath.replace(/\.md$/, '');
442→      imagesDir = `${mdFileBasename}_assets`;
443→
444→      const imageMap = await downloadImages(article.images, imagesDir);
445→
446→      // 替换内容中的图片占位符
447→      content = content.replace(/\{\{IMAGE_(\d+)\}\}/g, (match, index) => {
448→        const imgIndex = parseInt(index);
449→        if (imageMap[imgIndex]) {
450→          const { filename, alt } = imageMap[imgIndex];
451→          // 计算相对路径
452→          const relativePath = join(basename(imagesDir), filename);
453→          return `![${alt}](${relativePath})`;
454→        }
455→        // 被过滤掉的图片，移除占位符
456→        return '';
457→      });
458→
459→      // 清理多余的空行（移除图片后可能产生的连续空行）
460→      content = content.replace(/\n{3,}/g, '\n\n');
461→    }
462→
463→    // 生成 Markdown 内容
464→    const markdown = `# ${article.title}
465→
466→> 原文链接: ${article.url}
467→> 抓取时间: ${new Date().toLocaleString('zh-CN')}
468→
469→---
470→
471→${content}
472→`;
473→
474→    // 写入文件
475→    await writeFile(finalPath, markdown, 'utf-8');
476→    console.log(`✅ 文章已保存到: ${finalPath}`);
477→    if (imagesDir) {
478→      console.log(`📁 图片已保存到: ${imagesDir}`);
479→    }
480→
481→    return finalPath;
482→  } catch (error) {
483→    console.error('❌ 保存文件失败:', error.message);
484→    throw error;
485→  }
486→}
